#!/usr/bin/env python3
"""Validate persisted Leech visual sieve shell-cache sidecars."""

from __future__ import annotations

import argparse
import json
from pathlib import Path
from typing import Any


DEFAULT_REPORT = Path(
    ".a0/runs/jit-dequant/real/leech-visual-sieve.shell-cache.json"
)
CERTIFICATE_VERSION = "gnosis.leech-visual-sieve.shell-cache.v1"
EXPECTED_PROOF_MODULES = {
    "Gnosis.LeechNearestPoint",
    "Gnosis.AizawaLeechCompletion",
}


def read_json(path: Path) -> dict[str, Any]:
    if not path.exists():
        raise SystemExit(f"missing Leech visual sieve report: {path}")
    return json.loads(path.read_text())


def number(value: Any, name: str, path: Path) -> float:
    if not isinstance(value, (int, float)):
        raise SystemExit(f"{path}: {name} must be numeric")
    return float(value)


def nonnegative_int(value: Any, name: str, path: Path) -> int:
    if not isinstance(value, int) or value < 0:
        raise SystemExit(f"{path}: {name} must be a non-negative integer")
    return value


def validate_one(path: Path) -> None:
    payload = read_json(path)
    if payload.get("certificateVersion") != CERTIFICATE_VERSION:
        raise SystemExit(f"{path}: wrong certificateVersion")
    if payload.get("tool") != "bench-leech-visual-sieve":
        raise SystemExit(f"{path}: tool must be bench-leech-visual-sieve")

    config = payload.get("config")
    if not isinstance(config, dict):
        raise SystemExit(f"{path}: config must be an object")
    for key in ("width", "height", "stride", "repeats", "direct_keys", "sample_count"):
        value = nonnegative_int(config.get(key), f"config.{key}", path)
        if value <= 0:
            raise SystemExit(f"{path}: config.{key} must be positive")

    timing = payload.get("timing")
    if not isinstance(timing, dict):
        raise SystemExit(f"{path}: timing must be an object")
    repeats = config["repeats"]
    image_samples = timing.get("image_samples_ms")
    key_samples = timing.get("key_samples_ms")
    if not isinstance(image_samples, list) or len(image_samples) != repeats:
        raise SystemExit(f"{path}: timing.image_samples_ms length must equal repeats")
    if not isinstance(key_samples, list) or len(key_samples) != repeats:
        raise SystemExit(f"{path}: timing.key_samples_ms length must equal repeats")
    for key in ("image_median_ms", "image_per_sample_us", "key_median_ms", "key_per_key_us"):
        if number(timing.get(key), f"timing.{key}", path) < 0:
            raise SystemExit(f"{path}: timing.{key} must be non-negative")

    occupancy = payload.get("occupancy")
    if not isinstance(occupancy, dict):
        raise SystemExit(f"{path}: occupancy must be an object")
    origin = nonnegative_int(occupancy.get("origin_keys"), "occupancy.origin_keys", path)
    shell = nonnegative_int(occupancy.get("shell_keys"), "occupancy.shell_keys", path)
    unique = nonnegative_int(occupancy.get("unique_keys"), "occupancy.unique_keys", path)
    if origin + shell != config["sample_count"]:
        raise SystemExit(f"{path}: origin_keys + shell_keys must equal sample_count")
    if unique == 0 or unique > config["sample_count"]:
        raise SystemExit(f"{path}: occupancy.unique_keys must be in 1..sample_count")
    number(occupancy.get("mean_energy_sq"), "occupancy.mean_energy_sq", path)
    number(occupancy.get("mean_shell_margin"), "occupancy.mean_shell_margin", path)

    shell_cache = payload.get("shellCache")
    if not isinstance(shell_cache, dict):
        raise SystemExit(f"{path}: shellCache must be an object")
    addressable = nonnegative_int(
        shell_cache.get("addressable_shell_keys"),
        "shellCache.addressable_shell_keys",
        path,
    )
    hits = nonnegative_int(shell_cache.get("hits"), "shellCache.hits", path)
    saved = nonnegative_int(shell_cache.get("nodes_saved"), "shellCache.nodes_saved", path)
    address_variation = nonnegative_int(
        shell_cache.get("address_variation"),
        "shellCache.address_variation",
        path,
    )
    compressed_address_variation = nonnegative_int(
        shell_cache.get("compressed_address_variation"),
        "shellCache.compressed_address_variation",
        path,
    )
    vector_variation = nonnegative_int(
        shell_cache.get("vector_variation"),
        "shellCache.vector_variation",
        path,
    )
    compressed_vector_variation = nonnegative_int(
        shell_cache.get("compressed_vector_variation"),
        "shellCache.compressed_vector_variation",
        path,
    )
    hit_rate = number(shell_cache.get("hit_rate"), "shellCache.hit_rate", path)
    if addressable > shell:
        raise SystemExit(f"{path}: addressable_shell_keys cannot exceed shell_keys")
    if hits > addressable:
        raise SystemExit(f"{path}: shellCache.hits cannot exceed addressable_shell_keys")
    if saved > hits:
        raise SystemExit(f"{path}: shellCache.nodes_saved cannot exceed hits")
    expected_rate = 0.0 if addressable == 0 else hits / addressable
    if abs(hit_rate - expected_rate) > 1e-9:
        raise SystemExit(f"{path}: shellCache.hit_rate does not match hits/addressable")
    if compressed_address_variation > address_variation:
        raise SystemExit(f"{path}: compressed address variation cannot increase")
    if compressed_vector_variation > vector_variation:
        raise SystemExit(f"{path}: compressed vector variation cannot increase")

    admission = payload.get("cacheAdmission")
    if not isinstance(admission, dict) or not isinstance(admission.get("candidate"), bool):
        raise SystemExit(f"{path}: cacheAdmission.candidate must be boolean")
    if admission["candidate"] != (addressable > 0 and hits > 0):
        raise SystemExit(f"{path}: cacheAdmission.candidate must match shell cache evidence")

    proof_modules = {
        item.get("module")
        for item in payload.get("proof_spine", [])
        if isinstance(item, dict)
    }
    missing = EXPECTED_PROOF_MODULES - proof_modules
    if missing:
        raise SystemExit(f"{path}: missing proof modules: {sorted(missing)}")

    print(
        "OK "
        f"{path} shell={shell} addressable={addressable} hits={hits} "
        f"candidate={admission['candidate']}"
    )


def main() -> None:
    parser = argparse.ArgumentParser()
    parser.add_argument("paths", nargs="*", help="Sidecar paths to validate")
    args = parser.parse_args()

    paths = [Path(raw) for raw in args.paths] if args.paths else [DEFAULT_REPORT]
    for path in paths:
        validate_one(path)


if __name__ == "__main__":
    main()
